        this.dfs(master, 0, 0);
        if (this.target[0] === Infinity) {
            return -1;
        }
        return this.bfs();
    }

    cellKey(x, y) {
        return `${x},${y}`;
    }

    dfs(master, x, y) {
        if (master.isTarget()){
            this.target = [x, y];
        }
        for (let i = 0; i < 4; i++) {
