                this.grid.set(newPos, cost);
                this.dfs(master, nx, ny);
                master.move(this.oppositeDirChar[i]);
            }
        }
    }

    bfs() {
        let q = [[0, 0]];
        this.grid.set(this.cellKey(0, 0), 0);
        while (q.length > 0) {
            let pos = q.shift();
            let x = pos[0], y = pos[1];
            for (let i = 0; i < 4; i++) {
                let nx = x + this.dirs[i], ny = y + this.dirs[i + 1];
                let newPos = this.cellKey(nx, ny), oldPos = this.cellKey(x, y);
                let cost = this.grid.get(oldPos) + (this.grid.get(newPos) || 0);
