                    this.grid.set(newPos, cost);
                    if (nx !== this.target[0] || ny !== this.target[1]) {
                        q.push([nx, ny]);
                    }
                }
            }
        }
        return this.grid.get(this.cellKey(this.target[0], this.target[1])) || -1;
    }
}
