solutionCode.java:
    ```java
class Solution {
    int[] dirs = {-1, 0, 1, 0, -1};
    char[] dirChar = {'U', 'R', 'D', 'L'};
    char[] oppositeDirChar = {'D', 'L', 'U', 'R'};
    HashMap<Pair<Integer, Integer>, Integer> grid = new HashMap<>();
    Pair<Integer, Integer> target = new Pair<>(Integer.MAX_VALUE, Integer.MAX_VALUE);

    public int findShortestPath(GridMaster master) {
        dfs(master, 0, 0);
        if (target.getKey() == Integer.MAX_VALUE) {
            return -1;
        }
        return bfs();
    }

    void dfs(GridMaster master, int x, int y) {
        if (master.isTarget()) {
            target = new Pair<>(x, y);
        }
        for (int i = 0; i < 4; i++) {
            int nx = x + dirs[i], ny = y + dirs[i + 1];
            Pair<Integer, Integer> newPos = new Pair<>(nx, ny);
            if (grid.containsKey(newPos)) continue;
            if (master.canMove(dirChar[i])) {
                int cost = master.move(dirChar[i]);
                grid.put(newPos, cost);
                dfs(master, nx, ny);
                master.move(oppositeDirChar[i]);
            }
        }
    }

    int bfs() {
        Queue<Pair<Integer, Integer>> q = new LinkedList<>();
        q.offer(new Pair<>(0, 0));
        grid.put(new Pair<>(0, 0), 0);
        while (!q.isEmpty()) {
            Pair<Integer, Integer> pos = q.poll();
            int x = pos.getKey(), y = pos.getValue();
            for (int i = 0; i < 4; i++) {
                int nx = x + dirs[i], ny = y + dirs[i + 1];
                Pair<Integer, Integer> newPos = new Pair<>(nx, ny), oldPos = new Pair<>(x, y);
                int cost = grid.get(oldPos) + grid.getOrDefault(newPos, 0);
                if (grid.containsKey(newPos) && grid.get(newPos) > cost) {
                    grid.put(newPos, cost);
                    if (nx != target.getKey() || ny != target.getValue()) {
                        q.offer(new Pair<>(nx, ny));
                    }
                }
            }
        }
        return grid.getOrDefault(target, -1);
    }
}
